//! attention-closure-benchmark — deterministic saved-work estimate for the
//! resolution-lift gate.
//!
//! This does not claim end-to-end latency. It counts optimizer work that the
//! distributed mesh avoids before doing standing-wave compression, speculative
//! verification, or head-pruning updates against an aliased attention trace.

use distributed_inference::attention_closure_benchmark::{
    attention_closure_benchmark_json_pretty, build_attention_closure_benchmark_report,
    AttentionClosureBenchmarkConfig,
};

#[derive(Debug, Clone, Copy)]
struct Args {
    json: bool,
    config: AttentionClosureBenchmarkConfig,
}

fn parse_flag(flag: &str) -> bool {
    std::env::args().any(|arg| arg == flag)
}

fn parse_usize(flag: &str, default: usize) -> Result<usize, String> {
    let mut args = std::env::args();
    while let Some(arg) = args.next() {
        if arg == flag {
            let value = args.next().ok_or_else(|| format!("{flag} needs a value"))?;
            return value
                .parse::<usize>()
                .map_err(|err| format!("invalid {flag} value {value:?}: {err}"));
        }
    }
    Ok(default)
}

fn parse_args() -> Result<Args, String> {
    let default = AttentionClosureBenchmarkConfig::default();
    Ok(Args {
        json: parse_flag("--json"),
        config: AttentionClosureBenchmarkConfig {
            heads: parse_usize("--heads", default.heads)?,
            coupling: parse_usize("--coupling", default.coupling)?,
            observer_resolution: parse_usize("--observer-resolution", default.observer_resolution)?,
            residue_threshold: parse_usize("--residue-threshold", default.residue_threshold)?,
            hidden_dim: parse_usize("--hidden-dim", default.hidden_dim)?,
            batch_size: parse_usize("--batch-size", default.batch_size)?,
            layer_count: parse_usize("--layers", default.layer_count)?,
            standing_count: parse_usize("--standing-count", default.standing_count)?,
            requested_speculative_depth: parse_usize(
                "--spec-depth",
                default.requested_speculative_depth,
            )?,
            speculative_candidates: parse_usize(
                "--spec-candidates",
                default.speculative_candidates,
            )?,
            head_prune_candidates: parse_usize(
                "--head-prune-candidates",
                default.head_prune_candidates,
            )?,
            head_dim: parse_usize("--head-dim", default.head_dim)?,
        },
    })
}

fn main() -> Result<(), String> {
    let args = parse_args().inspect_err(|_| {
        eprintln!(
            "usage: attention-closure-benchmark [--heads N] [--observer-resolution N] \
             [--coupling N] [--hidden-dim N] [--layers N] [--standing-count N] \
             [--spec-depth N] [--json]"
        );
    })?;

    let report = build_attention_closure_benchmark_report(args.config);

    if args.json {
        println!(
            "{}",
            attention_closure_benchmark_json_pretty(args.config)
                .map_err(|err| format!("failed to serialize benchmark JSON: {err}"))?
        );
        return Ok(());
    }

    println!("attention-closure-benchmark");
    println!("  heads:                 {}", report.heads);
    println!("  observer_resolution:   {}", report.observer_resolution);
    println!("  source_resolution:     {}", report.source_resolution);
    println!("  head_trace:            {:?}", report.head_trace);
    println!("  state:                 {}", report.state);
    println!("  policy:                {}", report.policy);
    println!("  theorem_lineage:");
    for theorem in &report.theorem_lineage {
        println!("    - {}", theorem);
    }
    println!("  preserve_heads:        {}", report.preserve_heads);
    println!(
        "  allow_speculation:     {}",
        report.allow_speculative_decode
    );
    println!(
        "  allow_compression:     {}",
        report.allow_standing_wave_compression
    );
    println!(
        "  baseline_units:        {}",
        report.baseline_optimizer_units
    );
    println!("  gated_units:           {}", report.gated_optimizer_units);
    println!(
        "  avoided_units:         {}",
        report.avoided_optimizer_units
    );
    println!(
        "  avoided_spec_units:    {}",
        report.avoided_speculative_units
    );
    println!(
        "  preserved_prune_units: {}",
        report.preserved_head_prune_units
    );
    println!(
        "  route_bytes_full:      {}",
        report.full_route_bytes_when_lifted
    );
    println!(
        "  route_bytes_compressed_if_stable: {}",
        report.compressed_route_bytes_if_stable
    );

    Ok(())
}
